SELECT operation_type_id, operation_type_name
FROM well_operation_types
WHERE operation_type_code = 'type_code_example';

SELECT pool_id, COUNT(well_id) AS number_of_wells
FROM well_pools
GROUP BY pool_id;

SELECT ws.status_name, COUNT(*) AS well_count
FROM well_status ws
GROUP BY ws.status_name;

SELECT pool_depletion_type_id, pool_depletion_type_name
FROM pool_depletion_types
WHERE pool_depletion_type_name NOT LIKE '%Urgent%';
